import{_ as n,c as a,o as e,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"命令：監控與修剪 | opencode-dynamic-context-pruning","description":"學習使用 DCP 的 4 個命令監控和手動修剪。教你 /dcp context 查看對話，/dcp stats 查看統計，/dcp sweep 手動觸發修剪。","frontmatter":{"title":"命令：監控與修剪 | opencode-dynamic-context-pruning","sidebarTitle":"監控 Token、手動修剪","subtitle":"DCP 命令使用指南：監控與手動修剪","description":"學習使用 DCP 的 4 個命令監控和手動修剪。教你 /dcp context 查看對話，/dcp stats 查看統計，/dcp sweep 手動觸發修剪。","tags":["DCP 命令","Token 監控","手動修剪"],"prerequisite":["start-getting-started","platforms-auto-pruning"],"order":3},"headers":[],"relativePath":"zh-tw/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md","filePath":"zh-tw/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"}'),o={name:"zh-tw/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"};function p(d,s,l,c,i,r){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="dcp-命令使用指南-監控與手動修剪" tabindex="-1">DCP 命令使用指南：監控與手動修剪 <a class="header-anchor" href="#dcp-命令使用指南-監控與手動修剪" aria-label="Permalink to &quot;DCP 命令使用指南：監控與手動修剪&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>使用 <code>/dcp context</code> 查看目前對話的 Token 使用分佈</li><li>使用 <code>/dcp stats</code> 查看累計修剪統計</li><li>使用 <code>/dcp sweep [n]</code> 手動觸發修剪</li><li>理解受保護工具和檔案的保護機制</li><li>了解 Token 計算策略和節省效果</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>長對話中，Token 消耗越來越快，但你不知道：</p><ul><li>目前對話的 Token 都花在哪了？</li><li>DCP 究竟幫你省了多少？</li><li>怎麼手動清理那些不再需要的工具輸出？</li><li>哪些工具會被保護，不會被修剪？</li></ul><p>這些問題不搞清楚，你可能無法充分利用 DCP 的最佳化效果，甚至可能在關鍵時刻誤刪重要資訊。</p><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><p>當你：</p><ul><li>想了解目前對話的 Token 構成</li><li>需要快速清理對話歷史</li><li>想驗證 DCP 的修剪效果</li><li>準備開始新的任務前做一次上下文清理</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>DCP 提供了 4 個 Slash 命令，幫助你監控和控制 Token 使用：</p><table tabindex="0"><thead><tr><th>命令</th><th>用途</th><th>適用情境</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>顯示說明</td><td>忘記命令時查看</td></tr><tr><td><code>/dcp context</code></td><td>分析目前對話 Token 分佈</td><td>了解上下文構成</td></tr><tr><td><code>/dcp stats</code></td><td>查看累計修剪統計</td><td>驗證長期效果</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>手動修剪工具</td><td>快速減少上下文大小</td></tr></tbody></table><p><strong>受保護機制</strong>：</p><p>所有修剪操作都會自動跳過：</p><ul><li><strong>受保護工具</strong>：<code>task</code>、<code>todowrite</code>、<code>todoread</code>、<code>discard</code>、<code>extract</code>、<code>batch</code>、<code>write</code>、<code>edit</code>、<code>plan_enter</code>、<code>plan_exit</code></li><li><strong>受保護檔案</strong>：符合設定中的 <code>protectedFilePatterns</code> 的檔案路徑</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>受保護工具和受保護檔案的設定可以透過設定檔自訂。詳見<a href="./../../start/configuration/">設定全解</a>。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-查看說明資訊" tabindex="-1">第 1 步：查看說明資訊 <a class="header-anchor" href="#第-1-步-查看說明資訊" aria-label="Permalink to &quot;第 1 步：查看說明資訊&quot;">​</a></h3><p>在 OpenCode 對話框中輸入 <code>/dcp</code>。</p><p><strong>你應該看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Commands                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /dcp context      Show token usage breakdown for current session</span></span>
<span class="line"><span>  /dcp stats        Show DCP pruning statistics</span></span>
<span class="line"><span>  /dcp sweep [n]    Prune tools since last user message, or last n tools</span></span></code></pre></div><p><strong>檢查點 ✅</strong>：確認看到了 3 個子命令的說明。</p><h3 id="第-2-步-分析目前對話-token-分佈" tabindex="-1">第 2 步：分析目前對話 Token 分佈 <a class="header-anchor" href="#第-2-步-分析目前對話-token-分佈" aria-label="Permalink to &quot;第 2 步：分析目前對話 Token 分佈&quot;">​</a></h3><p>輸入 <code>/dcp context</code> 查看目前對話的 Token 使用情況。</p><p><strong>你應該看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                  DCP Context Analysis                     │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session Context Breakdown:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System         15.2% │████████████████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│  25.1K tokens</span></span>
<span class="line"><span>User            5.1% │████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│   8.4K tokens</span></span>
<span class="line"><span>Assistant       35.8% │██████████████████████████████████████▒▒▒▒▒▒▒│  59.2K tokens</span></span>
<span class="line"><span>Tools (45)      43.9% │████████████████████████████████████████████████│  72.6K tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary:</span></span>
<span class="line"><span>  Pruned:          12 tools (~15.2K tokens)</span></span>
<span class="line"><span>  Current context: ~165.3K tokens</span></span>
<span class="line"><span>  Without DCP:     ~180.5K tokens</span></span></code></pre></div><p><strong>Token 分類說明</strong>：</p><table tabindex="0"><thead><tr><th>分類</th><th>計算方式</th><th>說明</th></tr></thead><tbody><tr><td><strong>System</strong></td><td><code>firstAssistant.input + cache.read - tokenizer(firstUserMessage)</code></td><td>系統提示詞</td></tr><tr><td><strong>Tools</strong></td><td><code>tokenizer(toolInputs + toolOutputs) - prunedTokens</code></td><td>工具呼叫（已扣除修剪部分）</td></tr><tr><td><strong>User</strong></td><td><code>tokenizer(all user messages)</code></td><td>所有使用者訊息</td></tr><tr><td><strong>Assistant</strong></td><td><code>total - system - user - tools</code></td><td>AI 文字輸出 + 推理 Token</td></tr></tbody></table><p><strong>檢查點 ✅</strong>：確認看到了各分類的 Token 佔比和數量。</p><h3 id="第-3-步-查看累計修剪統計" tabindex="-1">第 3 步：查看累計修剪統計 <a class="header-anchor" href="#第-3-步-查看累計修剪統計" aria-label="Permalink to &quot;第 3 步：查看累計修剪統計&quot;">​</a></h3><p>輸入 <code>/dcp stats</code> 查看歷史累計的修剪效果。</p><p><strong>你應該看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                    DCP Statistics                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens pruned: ~15.2K</span></span>
<span class="line"><span>  Tools pruned:   12</span></span>
<span class="line"><span></span></span>
<span class="line"><span>All-time:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens saved:  ~284.5K</span></span>
<span class="line"><span>  Tools pruned:   156</span></span>
<span class="line"><span>  Sessions:       8</span></span></code></pre></div><p><strong>統計說明</strong>：</p><ul><li><strong>Session</strong>：目前對話的修剪資料（記憶體中）</li><li><strong>All-time</strong>：所有歷史對話的累計資料（磁碟持久化）</li></ul><p><strong>檢查點 ✅</strong>：確認看到了目前對話和歷史累計的修剪統計。</p><h3 id="第-4-步-手動修剪工具" tabindex="-1">第 4 步：手動修剪工具 <a class="header-anchor" href="#第-4-步-手動修剪工具" aria-label="Permalink to &quot;第 4 步：手動修剪工具&quot;">​</a></h3><p>有兩種方式使用 <code>/dcp sweep</code>：</p><h4 id="方式一-修剪上一條使用者訊息後的所有工具" tabindex="-1">方式一：修剪上一條使用者訊息後的所有工具 <a class="header-anchor" href="#方式一-修剪上一條使用者訊息後的所有工具" aria-label="Permalink to &quot;方式一：修剪上一條使用者訊息後的所有工具&quot;">​</a></h4><p>輸入 <code>/dcp sweep</code>（不帶參數）。</p><p><strong>你應該看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept 8 tool(s) since previous user message.</span></span>
<span class="line"><span>Tokens saved: ~12,345</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/config.ts</span></span>
<span class="line"><span>  • Read: src/utils.ts</span></span>
<span class="line"><span>  • Bash: npm test</span></span>
<span class="line"><span>  • Read: package.json</span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span></code></pre></div><h4 id="方式二-修剪最後-n-個工具" tabindex="-1">方式二：修剪最後 N 個工具 <a class="header-anchor" href="#方式二-修剪最後-n-個工具" aria-label="Permalink to &quot;方式二：修剪最後 N 個工具&quot;">​</a></h4><p>輸入 <code>/dcp sweep 5</code> 修剪最後 5 個工具。</p><p><strong>你應該看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept last 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span>
<span class="line"><span>  • Bash: npm run build</span></span></code></pre></div><p><strong>受保護工具提示</strong>：</p><p>如果跳過了受保護工具，輸出會顯示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Swept 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span>(2 protected tool(s) skipped)</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>受保護工具（如 <code>write</code>、<code>edit</code>）和受保護檔案路徑會被自動跳過，不會被修剪。</p></div><p><strong>檢查點 ✅</strong>：確認看到了修剪的工具清單和節省的 Token 數量。</p><h3 id="第-5-步-再次查看修剪效果" tabindex="-1">第 5 步：再次查看修剪效果 <a class="header-anchor" href="#第-5-步-再次查看修剪效果" aria-label="Permalink to &quot;第 5 步：再次查看修剪效果&quot;">​</a></h3><p>修剪後，再次輸入 <code>/dcp context</code> 查看新的 Token 分佈。</p><p><strong>你應該看到</strong>：</p><ul><li><code>Tools</code> 分類佔比下降</li><li><code>Summary</code> 中顯示已修剪的工具數增加</li><li><code>Current context</code> 總數減少</li></ul><p><strong>檢查點 ✅</strong>：確認 Token 使用量明顯減少。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="❌-錯誤-誤刪重要工具" tabindex="-1">❌ 錯誤：誤刪重要工具 <a class="header-anchor" href="#❌-錯誤-誤刪重要工具" aria-label="Permalink to &quot;❌ 錯誤：誤刪重要工具&quot;">​</a></h3><p><strong>情境</strong>：你剛用 <code>write</code> 工具寫了一個關鍵檔案，然後執行 <code>/dcp sweep</code>。</p><p><strong>錯誤結果</strong>：<code>write</code> 工具被修剪，AI 可能不知道檔案已建立。</p><p><strong>正確做法</strong>：</p><ul><li><code>write</code>、<code>edit</code> 等工具預設受保護</li><li>不要手動修改 <code>protectedTools</code> 設定刪除這些工具</li><li>關鍵任務完成後等待幾個回合再清理</li></ul><h3 id="❌-錯誤-修剪時機不當" tabindex="-1">❌ 錯誤：修剪時機不當 <a class="header-anchor" href="#❌-錯誤-修剪時機不當" aria-label="Permalink to &quot;❌ 錯誤：修剪時機不當&quot;">​</a></h3><p><strong>情境</strong>：對話剛開始，只有幾個工具呼叫就執行 <code>/dcp sweep</code>。</p><p><strong>錯誤結果</strong>：節省的 Token 很少，反而可能影響上下文連貫性。</p><p><strong>正確做法</strong>：</p><ul><li>等對話進行到一定程度（如 10+ 個工具呼叫）再清理</li><li>開始新任務前清理上一輪的工具輸出</li><li>結合 <code>/dcp context</code> 判斷是否值得清理</li></ul><h3 id="❌-錯誤-過度依賴手動修剪" tabindex="-1">❌ 錯誤：過度依賴手動修剪 <a class="header-anchor" href="#❌-錯誤-過度依賴手動修剪" aria-label="Permalink to &quot;❌ 錯誤：過度依賴手動修剪&quot;">​</a></h3><p><strong>情境</strong>：每次對話都手動執行 <code>/dcp sweep</code>。</p><p><strong>錯誤結果</strong>：</p><ul><li>自動修剪策略（去重、覆蓋寫入、清除錯誤）被浪費</li><li>增加操作負擔</li></ul><p><strong>正確做法</strong>：</p><ul><li>預設開啟自動修剪策略（設定：<code>strategies.*.enabled</code>）</li><li>手動修剪作為補充，在必要時使用</li><li>透過 <code>/dcp stats</code> 驗證自動修剪效果</li></ul><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>DCP 的 4 個命令幫助你監控和控制 Token 使用：</p><table tabindex="0"><thead><tr><th>命令</th><th>核心功能</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>顯示說明資訊</td></tr><tr><td><code>/dcp context</code></td><td>分析目前對話 Token 分佈</td></tr><tr><td><code>/dcp stats</code></td><td>查看累計修剪統計</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>手動修剪工具</td></tr></tbody></table><p><strong>Token 計算策略</strong>：</p><ul><li>System：系統提示詞（從第一條回應推算）</li><li>Tools：工具輸入輸出（扣除修剪部分）</li><li>User：所有使用者訊息（估算）</li><li>Assistant：AI 輸出 + 推理 Token（殘差）</li></ul><p><strong>受保護機制</strong>：</p><ul><li>受保護工具：<code>task</code>、<code>todowrite</code>、<code>todoread</code>、<code>discard</code>、<code>extract</code>、<code>batch</code>、<code>write</code>、<code>edit</code>、<code>plan_enter</code>、<code>plan_exit</code></li><li>受保護檔案：設定的 glob 模式</li><li>所有修剪操作自動跳過這些內容</li></ul><p><strong>最佳實踐</strong>：</p><ul><li>定期查看 <code>/dcp context</code> 了解 Token 構成</li><li>新任務前執行 <code>/dcp sweep</code> 清理歷史</li><li>依賴自動修剪，手動修剪作為補充</li><li>透過 <code>/dcp stats</code> 驗證長期效果</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../../advanced/protection/">保護機制</a></strong>。</p><p>你會學到：</p><ul><li>回合保護如何防止誤修剪</li><li>如何自訂受保護工具清單</li><li>受保護檔案模式的設定方法</li><li>子代理對話的特殊處理</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>/dcp 說明命令</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/help.ts" target="_blank" rel="noreferrer"><code>lib/commands/help.ts</code></a></td><td>19-32</td></tr><tr><td>/dcp context 命令</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>238-247</td></tr><tr><td>Token 計算策略</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>5-38</td></tr><tr><td>/dcp stats 命令</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/stats.ts" target="_blank" rel="noreferrer"><code>lib/commands/stats.ts</code></a></td><td>46-67</td></tr><tr><td>/dcp sweep 命令</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/sweep.ts" target="_blank" rel="noreferrer"><code>lib/commands/sweep.ts</code></a></td><td>123-259</td></tr><tr><td>受保護工具設定</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/config.ts" target="_blank" rel="noreferrer"><code>lib/config.ts</code></a></td><td>461</td></tr><tr><td>預設受保護工具清單</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/README.md" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>150-151</td></tr></tbody></table><p><strong>關鍵常數</strong>：</p><ul><li><code>DEFAULT_PROTECTED_TOOLS</code>：預設受保護工具清單</li></ul><p><strong>關鍵函式</strong>：</p><ul><li><code>handleHelpCommand()</code>：處理 /dcp 說明命令</li><li><code>handleContextCommand()</code>：處理 /dcp context 命令</li><li><code>analyzeTokens()</code>：計算各類別的 Token 數量</li><li><code>handleStatsCommand()</code>：處理 /dcp stats 命令</li><li><code>handleSweepCommand()</code>：處理 /dcp sweep 命令</li><li><code>buildToolIdList()</code>：建構工具 ID 清單</li></ul></details>`,88)])])}const g=n(o,[["render",p]]);export{u as __pageData,g as default};
